1266	static void PatchDistanceCodesForBuggyDecoders(unsigned *d_lengths)
1267	/* d_lengths holds the full DEFLATE distance alphabet (ZOPFLI_NUM_D entries).
1268	   The scan reads indices [0, 30) and the patch writes indices 0 and 1, so the
1269	   whole accessed range is within the object. */
