1271	    __CPROVER_is_fresh(d_lengths, (size_t)ZOPFLI_NUM_D * sizeof(*d_lengths)))
1272	/* Each entry is a Huffman code length, bounded by 15 in DEFLATE. */
1273	__CPROVER_requires(__CPROVER_forall {
1274	    size_t kd; (kd < (size_t)ZOPFLI_NUM_D) ==> (d_lengths[kd] <= 15)
1275	})
1276	/* The patch only ever touches the first two distance codes. */
1277	__CPROVER_assigns(d_lengths[0], d_lengths[1])
